import React, { useState,useRef, useEffect } from 'react'
import '../css/Traininfo.css'
import Seat_selection from '../components/seat_selection'
import axios from 'axios'
export default function Traininfo() {
  const DDD=useRef(null)
  const [stations,setStaions]=useState()

  let [see,setSee]=useState(false)
  const [search,setSearch]=useState('')

  useEffect(()=>{
    const fetch_data=async ()=>{
      axios.get('http://127.0.0.1:8000/api/get_stations')
      .then((res)=>{
        console.log(res.data.stations)
        setStaions(res.data.stations)

      })
    }

    fetch_data();
    setTimeout(() => {
      fetch_data()
    }, 5000);
  })
  console.log(stations)
  return (
    <div>
      <div className='drop'>
        <div  onClick={()=>setSee(!see)} style={{cursor:'pointer'}} >clickkkk</div>
        <div className='ddd' ref={DDD} style={{ maxHeight: see? `${DDD.current.scrollHeight}px` : '0px',
        overflow:'hidden',transition:'all 0.34s ease-in'}}>

         <Seat_selection/>



        
        </div>
        
        {/* <div>
          <Seat_selection/>
        </div> */}

      </div>
      <input type="text" placeholder='search staions' onChange={(e)=>setSearch(e.target.value)} />

      <div>

      </div>

      {/* <p>{DDD.current.clientHeight}</p> */}

    </div>
  )
}
